mapper.select:
select DISTINCT j.check_status As checkStat,j.task_notice_status As checkNoticeStat,d.sample_id As sampleId from jt_check_task j
   left join jt_entrust_check_item d on j.entrust_id=d.entrust_id
   where j.entrust_id=#{id}

SELECT DISTINCT a.entrust_id As entrustId,a.entrust_status As status, a.entrust_number As entrustCode, b.com_name As entrustDept,c.accept_time As entrustTime from jt_entrust_info a left join company b on a.entrust_company_id=b.com_id left join jt_entrust_check_info c on a.entrust_id=c.entrust_id left join jt_sample_info s on s.entrust_id=a.entrust_id left join jt_report_info jri on s.sample_id = jri.sample_id where c.accept_time >= #{startTime} and c.accept_time<= #{endTime} and a.crm=#{adminId}
AND jri.flow_status = 3
AND jri.flow_status != 3
